            do = dist(ox, oy, rx, ry)
            adv = do - ds
            # Tie-break: prefer smaller ds, then higher total reach, then lexicographic.
            key = (adv, -ds, -(ds + do), -rx, -ry)
            if best is None or key > best[0]:
                best = (key, rx, ry)
        _, tx, ty = best
